        <rect x="0" y="0" width="600" height="520" fill="url(#rBg)" rx="12"/>

        <!-- Title -->
        <text x="300" y="35" text-anchor="middle" fill="#d4a843" font-size="16" font-weight="bold" letter-spacing="1">MODEL ABCDE — REBT</text>
