          <path d="M 220 150 Q 170 120 180 180 Q 190 220 230 200 Q 260 210 230 170 Q 230 140 220 150 Z" fill="url(#petalGrad)" stroke="#d4a843" stroke-width="1.5" opacity="0.9"/>
